class Solution {

    public List<List<Integer>> findCombinationSum2(List<Integer> candidateNumbers, int targetSum) {
        Collections.sort(candidateNumbers);
        List<List<Integer>> result = new ArrayList<>();
        List<Integer> current = new ArrayList<>();

        backtrack(0, targetSum, candidateNumbers, current, result);
        return result;
    }

    private void backtrack(int index, int target, List<Integer> nums,
                           List<Integer> current, List<List<Integer>> result) {

        if (target == 0) {
            result.add(new ArrayList<>(current));
            return;
        }

        for (int i = index; i < nums.size(); i++) {
            // Skip duplicates
            if (i > index && nums.get(i).equals(nums.get(i - 1)))
                continue;

            if (nums.get(i) > target)
                break;

            current.add(nums.get(i));
            backtrack(i + 1, target - nums.get(i), nums, current, result);
            current.remove(current.size() - 1);
        }
    }
}

