class Solution {
    findCombinationSum2(candidateNumbers, targetSum) {
        candidateNumbers.sort((a, b) => a - b);
        const result = [];
        const current = [];

        const backtrack = (start, target) => {
            if (target === 0) {
                result.push([...current]);
                return;
            }

            for (let i = start; i < candidateNumbers.length; i++) {
                // Skip duplicates
                if (i > start && candidateNumbers[i] === candidateNumbers[i - 1]) continue;

                if (candidateNumbers[i] > target) break;

                current.push(candidateNumbers[i]);
                backtrack(i + 1, target - candidateNumbers[i]);
                current.pop();
            }
        };

        backtrack(0, targetSum);
        return result;
    }
}
